import{_ as e,o as l,c as i,f as o}from"./app-19f36e20.js";const d={},c=o('<h1 id="gdscript-语法约定" tabindex="-1"><a class="header-anchor" href="#gdscript-语法约定" aria-hidden="true">#</a> GDScript 语法约定</h1><h2 id="语法约定" tabindex="-1"><a class="header-anchor" href="#语法约定" aria-hidden="true">#</a> #语法约定</h2><ul><li><strong>变量</strong><ul><li><code>var 关键字</code> 申明一个变量</li><li><code>const 关键字</code> 申明一个常量</li></ul></li><li><strong>数据</strong><ul><li>基本数据类型：包括整数、浮点数、布尔值、字符串和枚举。</li><li>复合数据类型：包括数组、字典、列表和集合。</li><li>对象数据类型：包括场景、节点、材质、纹理、音频和动画。</li></ul></li><li><strong>运算符</strong><ul><li><code>and(与) or(或) not(非)</code> 逻辑运算符</li></ul></li><li><strong>条件语句</strong><ul><li><code>if …… elif …… else ……</code> 条件分支语句</li><li><code>switch &amp;&amp; case</code> 条件分支语句</li></ul></li><li><strong>循环执行</strong><ul><li><code>for 循环</code>：用于在一个范围内执行代码块。</li><li><code>while 循环</code>：用于在一个条件成立时执行代码块。</li><li><code>do-while 循环</code>：用于在一个条件成立时执行代码块，然后再判断条件是否成立。</li></ul></li><li><strong>函数</strong><ul><li><code>func 关键字</code> 申明函数</li><li><code>pass 关键字</code> 通常用作占位符，用于指示某个代码块暂时不需要执行任何操作。</li></ul></li><li><strong>面向对象</strong><ul><li><code>self 关键字</code> 表示获取当前节点。</li></ul></li></ul><h2 id="语法特性" tabindex="-1"><a class="header-anchor" href="#语法特性" aria-hidden="true">#</a> #语法特性</h2><div class="custom-container danger"><p class="custom-container-title">什么是虚拟方法？</p><p>虚拟方法（Virtual Methods），是指可以在子类中被重写的方法。例如 _ready()、_process(delta)等等</p></div><h4 id="场景与节点" tabindex="-1"><a class="header-anchor" href="#场景与节点" aria-hidden="true">#</a> 场景与节点</h4><ul><li>虚拟方法 <ul><li><code>_ready()</code>: 当节点第一次进入场景树时调用，往往用来设置节点的默认状态。</li><li><code>_process(delta: float)</code>: 每帧调用一次，delta 是自上一帧结束时到当前帧结束的时间间隔。</li><li><code>_input(event: InputEvent)</code>: 当节点接收到输入事件时，该函数会被调用。</li></ul></li><li>操作场景树 <ul><li><code>Node.get_tree()</code>, 用于返回包含该节点的 <strong>场景树(SceneTree)</strong>。</li><li><code>SceneTree.quit()</code>, 用于退出 Godot 引擎。</li><li><code>SceneTree.change_scene_to_file()</code> 用于加载并切换到另一个场景文件。</li></ul></li><li>操作节点 <ul><li>获取节点对象 <ul><li><code>$ 符号</code>，根据节点名称，快速地获取当前场景中的节点，例如<code>$Button、$ui/ui_end</code>。</li><li><code>Node.get_parent()</code>: 返回当前节点的父节点，如果节点缺少父节点，则返回 null。</li><li><code>Node.get_node(path: NodePath)</code> 根据节点路径来获取节点对象。</li></ul></li><li>显示（或隐藏）节点 <ul><li><code>Node.visible = true</code>: 显示节点</li><li><code>Node.visible = false</code>: 隐藏节点</li></ul></li><li>增加节点 <ul><li><code>Node.add_child(node)</code> 添加子节点</li></ul></li><li>删除节点 <ul><li><code>Node.queue_free()</code> 在当前帧结束的时候，删除该节点。</li></ul></li></ul></li><li>信号 <ul><li><code>signal 关键字</code>，自定义信号，例如<code>signal destroyed</code></li><li><code>emit_signal() 函数</code>，发送信号，例如<code>emit_signal(&quot;destroyed&quot;)</code></li><li><code>Signal.connect() 函数</code>，监听信号，例如<code>$player.destroyed.connect(callback)</code></li></ul></li></ul><h4 id="资源" tabindex="-1"><a class="header-anchor" href="#资源" aria-hidden="true">#</a> 资源</h4><ul><li><code>@GDScript.preload(path)</code> 预加载，在脚本解析时，加载文件。例如<code>preload(&quot;res://diamond.tscn&quot;)</code></li><li><code>PackedScene.instantiate()</code> 用于实例化场景资源。</li></ul><h4 id="数学" tabindex="-1"><a class="header-anchor" href="#数学" aria-hidden="true">#</a> 数学</h4><ul><li>随机数 <ul><li><code>randf_range(from, to)</code> 返回 from 和 to（包含）之间的随机浮点值。</li></ul></li><li>线性代数 <ul><li>二维向量 <ul><li>创建二维向量数值<code>例如，Vector2() =&gt; (0, 0) || Vector2(1, 2) =&gt; (1, 2)</code></li></ul></li></ul></li></ul>',11),t=[c];function a(r,n){return l(),i("div",null,t)}const u=e(d,[["render",a],["__file","gdscript-grammar.html.vue"]]);export{u as default};
